def find_duplicates_with_hash_set(arr):
    seen = set()
    duplicates = set()

    for item in arr:
        if item in seen:
            duplicates.add(item)
        else:
            seen.add(item)

    return list(duplicates)

if __name__ == '__main__':
    # Örnek kullanım:
    my_array = [1, 2, 3, 4, 2, 5, 6, 1, 7, 8, 8, 9]
    result = find_duplicates_with_hash_set(my_array)
    print(result) # Çıktı: [1, 2, 8] (sıra garanti edilmez)

    my_array_2 = [10, 20, 30, 40, 50]
    result_2 = find_duplicates_with_hash_set(my_array_2)
    print(result_2) # Çıktı: []

    my_array_3 = ['apple', 'banana', 'apple', 'orange', 'banana', 'grape']
    result_3 = find_duplicates_with_hash_set(my_array_3)
    print(result_3) # Çıktı: ['apple', 'banana'] (sıra garanti edilmez)
